#!/usr/bin/env bash
set -e

# Version for both zenoh-c and zenoh-cpp
ver_tag="1.9.0"

# Root directory of the script
root_dir="$(pwd)"

is_windows() {
  [[ "$OSTYPE" == "msys"* || "$OSTYPE" == "cygwin"* || "$OSTYPE" == "mingw"* || "$OSTYPE" == "win32"* ]]
}

# Install rust toolchain if cargo is missing.
ensure_cargo() {
  # 1) In Windows shells, cargo may be installed under USERPROFILE.
  # Prepend that location so command lookup can find cargo/rustup immediately.
  if is_windows && [ -n "$USERPROFILE" ] && command -v cygpath >/dev/null 2>&1; then
    export PATH="$(cygpath "$USERPROFILE")/.cargo/bin:$PATH"
  fi

  # 2) Load rustup's env script when present so current shell gets updated PATH.
  if [ -f "$HOME/.cargo/env" ]; then
    # shellcheck disable=SC1090
    source "$HOME/.cargo/env"
  fi

  # 3) Fast path: cargo already available, nothing else to do.
  if command -v cargo >/dev/null 2>&1; then
    echo "Found cargo: $(command -v cargo)"
    return
  fi

  echo "cargo is not found, installing rustup and cargo"

  if ! command -v curl >/dev/null 2>&1; then
    echo "Error: curl is required to install cargo via rustup"
    exit 1
  fi

  # 4) Install rustup/cargo non-interactively.
  curl --proto '=https' --tlsv1.2 -sSf https://sh.rustup.rs | sh -s -- -y

  # 5) Re-load shell env generated by rustup in this same process.
  if [ -f "$HOME/.cargo/env" ]; then
    # shellcheck disable=SC1090
    source "$HOME/.cargo/env"
  fi

  # 6) Add common cargo bin paths explicitly to handle shell/env variations.
  export PATH="$HOME/.cargo/bin:$PATH"
  if is_windows && [ -n "$USERPROFILE" ] && command -v cygpath >/dev/null 2>&1; then
    export PATH="$(cygpath "$USERPROFILE")/.cargo/bin:$PATH"
  fi

  # 7) Validate installation before continuing build steps.
  if ! command -v cargo >/dev/null 2>&1; then
    echo "Error: cargo installation failed"
    exit 1
  fi

  echo "Installed cargo: $(command -v cargo)"
}

# For Windows builds, force rustup/cargo to use the MSVC toolchain/target.
# This avoids GNU-target requirements (for example dlltool.exe) during zenoh build.
configure_rust_windows_toolchain() {
  if ! is_windows; then
    return
  fi

  local rust_msvc_toolchain="stable-x86_64-pc-windows-msvc"
  export RUSTUP_TOOLCHAIN="$rust_msvc_toolchain"
  export CARGO_BUILD_TARGET="x86_64-pc-windows-msvc"

  if command -v rustup >/dev/null 2>&1; then
    rustup toolchain install "$rust_msvc_toolchain" >/dev/null
    if command -v rustup.exe >/dev/null 2>&1; then
      rustup.exe toolchain install "$rust_msvc_toolchain" >/dev/null
    fi
  else
    echo "Warning: rustup not found in PATH; cannot enforce MSVC Rust toolchain"
  fi
}

# Install zenoh-c backend
install_zenoh_c() {
  local repo="zenoh-c"
  echo "Installing $repo ($ver_tag)"
  cd "$root_dir"

  if [ ! -d "$repo" ]; then
    git clone https://github.com/eclipse-zenoh/$repo.git --branch $ver_tag
    cd "$repo"
  else
    cd "$repo"
    git fetch --all
    git checkout $ver_tag
  fi

  mkdir -p build && cd build
  cmake .. $SHARED_CMAKE_ARGS \
           -DBUILD_SHARED_LIBS=ON \
           -DZENOHC_BUILD_WITH_UNSTABLE_API=ON

  cmake --build . --target install --config Release -j $NUM_JOBS

  echo "Installed $repo"
}

# Install zenoh-cpp aligned to the same version as zenoh-c
install_zenoh_cpp() {
  local repo="zenoh-cpp"
  echo "Installing $repo ($ver_tag)"
  cd "$root_dir"

  if [ ! -d "$repo" ]; then
    git clone https://github.com/eclipse-zenoh/$repo.git --branch $ver_tag
    cd "$repo"
  else
    cd "$repo"
    git fetch --all
    git checkout $ver_tag
  fi

  mkdir -p build && cd build
  cmake .. $SHARED_CMAKE_ARGS \
           -DBUILD_SHARED_LIBS=ON \
           -DZENOHCXX_ENABLE_TESTS=OFF \
           -DZENOHCXX_ENABLE_EXAMPLES=OFF \
           -DZENOHCXX_EXAMPLES_PROTOBUF=OFF

  cmake --build . --target install --config Release -j $NUM_JOBS

  echo "Installed $repo"
}

ensure_cargo
configure_rust_windows_toolchain
install_zenoh_c
install_zenoh_cpp
